#include <bits/stdc++.h>
using namespace std;
int main(){int n,c;scanf("%d %d",&n,&c);vector<long long>x(n);for(auto&v:x)scanf("%lld",&v);sort(x.begin(),x.end());long long lo=1,hi=x[n-1]-x[0],ans=0;while(lo<=hi){long long mid=(lo+hi)/2;int cnt=1;long long last=x[0];for(int i=1;i<n;i++)if(x[i]-last>=mid){cnt++;last=x[i];}if(cnt>=c){ans=mid;lo=mid+1;}else hi=mid-1;}printf("%lld\n",ans);}
